     1→import express from "express";
     2→import cors from "cors";
     3→import { WebSocketServer, WebSocket } from "ws";
     4→import { createServer } from "http";
     5→import { execSync, exec as execCb } from "child_process";
     6→import { promisify } from "util";
     7→
     8→const exec = promisify(execCb);
     9→import { existsSync, mkdirSync } from "fs";
    10→import { basename, join } from "path";
    11→import { getDb } from "./db.js";
    12→import { indexAllCheckpointsV2, indexAllShadowBranches } from "./indexer.js";
    13→import { setupLogContentFts, syncLogContentFts, searchLogContent } from "./search.js";
    14→
    15→// ─── Git user ─────────────────────────────────────────────────────────────────
    16→
    17→function gitConfigGet(key: string, cwd?: string): string | null {
    18→  try {
    19→    return execSync(`git config ${key}`, {
    20→      cwd,
    21→      encoding: "utf8",
    22→      stdio: ["ignore", "pipe", "ignore"],
    23→    }).trim() || null;
    24→  } catch { return null; }
    25→}
    26→
    27→function getGitUser(cwd?: string): { name: string | null; email: string | null } {
    28→  // Try local config first (cwd), then fall back to global
    29→  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
    30→  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
    31→  return { name, email };
    32→}
    33→
    34→// ─── Response types ───────────────────────────────────────────────────────────
    35→
    36→interface SessionResponse {
    37→  sessionId: string;
    38→  startedAt: string;
    39→  updatedAt: string;
    40→  cwd: string;
    41→  repoRoot: string | null;
    42→  repoName: string | null;
    43→  parentSessionId: string | null;
    44→  childSessionIds: string[];
    45→  gitUserName: string | null;
    46→  gitUserEmail: string | null;
    47→  prompt: string | null;
    48→  summary: string | null;
    49→  keywords: string[];
    50→  branch: string | null;
    51→  intent: string | null;
    52→  /** true when this session is currently indexed in a shadow branch */
    53→  isLive: boolean;
    54→}
    55→
    56→interface OverviewResponse {
    57→  sessionId: string;
    58→  summary: string;
    59→  keywords: string[];
    60→  startedAt: string;
    61→  endedAt: string;
    62→}
    63→
    64→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    65→
    66→// ─── Server ───────────────────────────────────────────────────────────────────
    67→
    68→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
    69→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
    70→  delete process.env.CLAUDECODE;
    71→
    72→  const db = await getDb(dbPath);
    73→
    74→  // Ensure FTS table exists and is up-to-date on startup
    75→  await setupLogContentFts(db);
    76→  await syncLogContentFts(db);
    77→
    78→  const app = express();
    79→  app.use(cors());
    80→  app.use(express.json());
    81→
    82→  // Resolve git user and repo name from repo config once at startup
    83→  const gitUser  = getGitUser(repoDir);
    84→  const repoName = repoDir ? basename(repoDir) : null;
    85→
    86→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
    87→  app.get("/api/sessions", async (_req, res) => {
    88→    try {
    89→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
    90→      const allMetas = await db.checkpointSessionMetadata.findMany({
    91→        select: {
    92→          sessionId: true,
    93→          checkpointId: true,
    94→          branch: true,
    95→          summary: { select: { intent: true } },
    96→        },
    97→        orderBy: { createdAt: "asc" },
    98→      });
    99→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   100→      for (const m of allMetas) {
   101→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   102→      }
   103→
   104→      // Git user per checkpoint (from commit author stored at index time)
   105→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   106→      const cpUserRows = allCheckpointIds.length > 0
   107→        ? await db.checkpointMetadata.findMany({
   108→            where: { checkpointId: { in: allCheckpointIds } },
   109→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   110→          })
   111→        : [];
   112→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   113→
   114→      const shadows = await db.shadowSession.findMany();
   115→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   116→
   117→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   118→      if (allIds.length === 0) {
   119→        res.json([]);
   120→        return;
   121→      }
   122→
   123→      // Min/max LogEvent timestamps per session
   124→      const times = await db.logEvent.groupBy({
   125→        by: ["sessionId"],
   126→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   127→        _min: { timestamp: true },
   128→        _max: { timestamp: true },
   129→      });
   130→      const timeMap = new Map(
   131→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   132→      );
   133→
   134→      // First cwd per session
   135→      const cwdRows = await db.logEvent.findMany({
   136→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   137→        distinct: ["sessionId"],
   138→        orderBy: { id: "asc" },
   139→        select: { sessionId: true, cwd: true },
   140→      });
   141→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   142→
   143→      const result: SessionResponse[] = allIds.map((sessionId) => {
   144→        const cp     = cpMap.get(sessionId) ?? null;
   145→        const shadow = shadowMap.get(sessionId) ?? null;
   146→        const t      = timeMap.get(sessionId);
   147→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   148→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   149→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   150→        return {
   151→          sessionId,
   152→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   153→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   154→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   155→          repoRoot:        repoDir ?? null,
   156→          repoName:        repoName,
   157→          parentSessionId: null,
   158→          childSessionIds: [],
   159→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   160→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   161→          prompt:          shadow?.prompt ?? null,
   162→          summary:         null,
   163→          keywords:        [],
   164→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   165→          intent:          cp?.intent ?? null,
   166→          isLive:          shadow !== null,
   167→        };
   168→      });
   169→
   170→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   171→      res.json(result);
   172→    } catch (err) {
   173→      res.status(500).json({ error: String(err) });
   174→    }
   175→  });
   176→
   177→  // GET /api/sessions/:id
   178→  app.get("/api/sessions/:id", async (req, res) => {
   179→    try {
   180→      const id = req.params.id;
   181→      const [latestMeta, shadow, firstEvent, lastEvent] = await Promise.all([
   182→        db.checkpointSessionMetadata.findFirst({
   183→          where: { sessionId: id },
   184→          select: { branch: true, checkpointId: true, summary: { select: { intent: true } } },
   185→          orderBy: { createdAt: "desc" },
   186→        }),
   187→        db.shadowSession.findUnique({ where: { sessionId: id } }),
   188→        db.logEvent.findFirst({
   189→          where: { sessionId: id },
   190→          orderBy: { id: "asc" },
   191→          select: { cwd: true, timestamp: true },
   192→        }),
   193→        db.logEvent.findFirst({
   194→          where: { sessionId: id, timestamp: { not: null } },
   195→          orderBy: { id: "desc" },
   196→          select: { timestamp: true },
   197→        }),
   198→      ]);
   199→      if (!latestMeta && !shadow) {
   200→        res.status(404).json({ error: "Session not found" });
   201→        return;
   202→      }
   203→      const cpMeta = latestMeta
   204→        ? await db.checkpointMetadata.findUnique({
   205→            where: { checkpointId: latestMeta.checkpointId },
   206→            select: { gitUserName: true, gitUserEmail: true },
   207→          })
   208→        : null;
   209→      const startedAt = firstEvent?.timestamp ?? shadow?.createdAt ?? null;
   210→      const updatedAt = lastEvent?.timestamp  ?? shadow?.createdAt ?? null;
   211→      res.json({
   212→        sessionId:       id,
   213→        startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
   214→        updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
   215→        cwd:             firstEvent?.cwd ?? shadow?.cwd ?? "",
   216→        repoRoot:        repoDir ?? null,
   217→        repoName:        repoName,
   218→        parentSessionId: null,
   219→        childSessionIds: [],
   220→        gitUserName:     cpMeta?.gitUserName ?? gitUser.name,
   221→        gitUserEmail:    cpMeta?.gitUserEmail ?? gitUser.email,
   222→        prompt:          shadow?.prompt ?? null,
   223→        summary:         null,
   224→        keywords:        [],
   225→        branch:          latestMeta?.branch ?? shadow?.gitBranch ?? null,
   226→        intent:          latestMeta?.summary?.intent ?? null,
   227→        isLive:          shadow !== null,
   228→      } satisfies SessionResponse);
   229→    } catch (err) {
   230→      res.status(500).json({ error: String(err) });
   231→    }
   232→  });
   233→
   234→  // GET /api/sessions/:id/overview
   235→  app.get("/api/sessions/:id/overview", async (req, res) => {
   236→    try {
   237→      const overview = await db.interactionOverview.findUnique({
   238→        where: { sessionId: req.params.id },
   239→      });
   240→      if (!overview) {
   241→        res.status(404).json({ error: "No overview for this session" });
   242→        return;
   243→      }
   244→      const result: OverviewResponse = {
   245→        sessionId: overview.sessionId,
   246→        summary: overview.summary,
   247→        keywords: overview.keywords ? (JSON.parse(overview.keywords) as string[]) : [],
   248→        startedAt: overview.startedAt.toISOString(),
   249→        endedAt: overview.endedAt.toISOString(),
   250→      };
   251→      res.json(result);
   252→    } catch (err) {
   253→      res.status(500).json({ error: String(err) });
   254→    }
   255→  });
   256→
   257→  // GET /api/v2/sessions/:id/log-events
   258→  app.get("/api/v2/sessions/:id/log-events", async (req, res) => {
   259→    try {
   260→      const events = await db.logEvent.findMany({
   261→        where:   { sessionId: req.params.id },
   262→        orderBy: { timestamp: "asc" },
   263→        include: {
   264→          contents:    { orderBy: { contentIndex: "asc" } },
   265→          usage:       true,
   266→          hookProgress: true,
   267→          systemData:  true,
   268→        },
   269→      });
   270→      res.json(events.map((e) => ({
   271→        id:              e.id,
   272→        uuid:            e.uuid,
   273→        sessionId:       e.sessionId,
   274→        parentUuid:      e.parentUuid,
   275→        type:            e.type,
   276→        timestamp:       e.timestamp?.toISOString() ?? null,
   277→        cwd:             e.cwd,
   278→        gitBranch:       e.gitBranch,
   279→        slug:            e.slug,
   280→        isSidechain:     e.isSidechain,
   281→        toolUseId:       e.toolUseId,
   282→        parentToolUseId: e.parentToolUseId,
   283→        contents: e.contents.map((c) => ({
   284→          contentType:       c.contentType,
   285→          contentIndex:      c.contentIndex,
   286→          text:              c.text,
   287→          thinking:          c.thinking,
   288→          toolUseId:         c.toolUseId,
   289→          toolName:          c.toolName,
   290→          toolInput:         c.toolInput ? (JSON.parse(c.toolInput) as unknown) : null,
   291→          toolResultContent: c.toolResultContent,
   292→          isError:           c.isError,
   293→        })),
   294→        usage: e.usage ? {
   295→          model:                    e.usage.model,
   296→          stopReason:               e.usage.stopReason,
   297→          inputTokens:              e.usage.inputTokens,
   298→          outputTokens:             e.usage.outputTokens,
   299→          cacheCreationInputTokens: e.usage.cacheCreationInputTokens,
   300→          cacheReadInputTokens:     e.usage.cacheReadInputTokens,
   301→        } : null,
   302→        hookProgress: e.hookProgress ? {
   303→          type:      e.hookProgress.type,
   304→          hookEvent: e.hookProgress.hookEvent,
   305→          hookName:  e.hookProgress.hookName,
   306→          command:   e.hookProgress.command,
   307→        } : null,
   308→        systemData: e.systemData ? {
   309→          subtype:               e.systemData.subtype,
   310→          hookCount:             e.systemData.hookCount,
   311→          stopReason:            e.systemData.stopReason,
   312→          preventedContinuation: e.systemData.preventedContinuation,
   313→          level:                 e.systemData.level,
   314→          durationMs:            e.systemData.durationMs,
   315→        } : null,
   316→      })));
   317→    } catch (err) {
   318→      res.status(500).json({ error: String(err) });
   319→    }
   320→  });
   321→
   322→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   323→
   324→  type V2Session = {
   325→    summary: {
   326→      intent: string; outcome: string;
   327→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   328→      frictionItems: { text: string }[];
   329→      repoLearnings: { text: string }[];
   330→      codeLearnings: { path: string; finding: string }[];
   331→      workflowLearnings: { text: string }[];
   332→    } | null;
   333→  };
   334→
   335→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   336→    return {
   337→      intent:            summary.intent,
   338→      outcome:           summary.outcome,
   339→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   340→      friction:          summary.frictionItems.map((r) => r.text),
   341→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   342→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   343→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   344→    };
   345→  }
   346→
   347→  const V2_SESSION_INCLUDE = {
   348→    summary: {
   349→      include: {
   350→        openItems:         true,
   351→        frictionItems:     true,
   352→        repoLearnings:     true,
   353→        codeLearnings:     true,
   354→        workflowLearnings: true,
   355→      },
   356→    },
   357→  } as const;
   358→
   359→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   360→
   361→  // GET /api/v2/checkpoints
   362→  app.get("/api/v2/checkpoints", async (_req, res) => {
   363→    try {
   364→      const checkpoints = await db.checkpointMetadata.findMany({
   365→        include: {
   366→          tokenUsage: true,
   367→          filesTouched: { include: { filePath: true } },
   368→        },
   369→      });
   370→
   371→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   372→
   373→      const sessions = await db.checkpointSessionMetadata.findMany({
   374→        where:   { checkpointId: { in: checkpointIds } },
   375→        orderBy: V2_SESSION_ORDER,
   376→        include: V2_SESSION_INCLUDE,
   377→      });
   378→
   379→      // Group sessions by checkpointId
   380→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   381→      for (const s of sessions) {
   382→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   383→        arr.push(s);
   384→        sessionsByCheckpoint.set(s.checkpointId, arr);
   385→      }
   386→
   387→      res.json(checkpoints.map((c) => {
   388→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   389→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   390→        const latestCreatedAt = cpSessions
   391→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   392→          .map((s) => s.createdAt)
   393→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   394→        return {
   395→          id:               c.id,
   396→          checkpointId:     c.checkpointId,
   397→          cliVersion:       c.cliVersion,
   398→          strategy:         c.strategy,
   399→          branch:           c.branch,
   400→          checkpointsCount: c.checkpointsCount,
   401→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   402→          tokenUsage: c.tokenUsage ? {
   403→            inputTokens:         c.tokenUsage.inputTokens,
   404→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   405→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   406→            outputTokens:        c.tokenUsage.outputTokens,
   407→            apiCallCount:        c.tokenUsage.apiCallCount,
   408→          } : null,
   409→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   410→          sessionCount:  cpSessions.length,
   411→          summary: summary ? mapV2Summary(summary) : null,
   412→        };
   413→      }));
   414→    } catch (err) {
   415→      res.status(500).json({ error: String(err) });
   416→    }
   417→  });
   418→
   419→  // GET /api/v2/checkpoints/:id
   420→  app.get("/api/v2/checkpoints/:id", async (req, res) => {
   421→    try {
   422→      const checkpointId = req.params.id;
   423→      const checkpoint = await db.checkpointMetadata.findUnique({
   424→        where: { checkpointId },
   425→        include: {
   426→          tokenUsage: true,
   427→          filesTouched: { include: { filePath: true } },
   428→        },
   429→      });
   430→      if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }
   431→
   432→      const sessions = await db.checkpointSessionMetadata.findMany({
   433→        where:   { checkpointId },
   434→        orderBy: V2_SESSION_ORDER,
   435→        include: V2_SESSION_INCLUDE,
   436→      });
   437→
   438→      const summary = sessions.find((s) => s.summary)?.summary ?? null;
   439→
   440→      res.json({
   441→        id:               checkpoint.id,
   442→        checkpointId:     checkpoint.checkpointId,
   443→        cliVersion:       checkpoint.cliVersion,
   444→        strategy:         checkpoint.strategy,
   445→        branch:           checkpoint.branch,
   446→        checkpointsCount: checkpoint.checkpointsCount,
   447→        tokenUsage: checkpoint.tokenUsage ? {
   448→          inputTokens:         checkpoint.tokenUsage.inputTokens,
   449→          cacheCreationTokens: checkpoint.tokenUsage.cacheCreationTokens,
   450→          cacheReadTokens:     checkpoint.tokenUsage.cacheReadTokens,
   451→          outputTokens:        checkpoint.tokenUsage.outputTokens,
   452→          apiCallCount:        checkpoint.tokenUsage.apiCallCount,
   453→        } : null,
   454→        filesTouched:  checkpoint.filesTouched.map((f) => f.filePath.path),
   455→        sessionCount:  sessions.length,
   456→        summary:       summary ? mapV2Summary(summary) : null,
   457→      });
   458→    } catch (err) {
   459→      res.status(500).json({ error: String(err) });
   460→    }
   461→  });
   462→
   463→  // GET /api/v2/checkpoints/:id/diff — raw unified diff for use with diff2html
   464→  app.get("/api/v2/checkpoints/:id/diff", async (req, res) => {
   465→    try {
   466→      if (!repoDir) { res.status(404).end(); return; }
   467→      const join = await db.checkpointIdGitOidJoin.findFirst({
   468→        where: { checkpointId: req.params.id },
   469→        select: { gitOid: true },
   470→      });
   471→      if (!join) { res.status(404).end(); return; }
   472→      const { stdout } = await exec(
   473→        `git -C ${JSON.stringify(repoDir)} diff-tree -p --no-commit-id -r ${join.gitOid}`,
   474→      );
   475→      res.set("Content-Type", "text/plain; charset=utf-8");
   476→      res.send(stdout);
   477→    } catch {
   478→      res.status(500).end();
   479→    }
   480→  });
   481→
   482→  // GET /api/v2/checkpoints/:id/diff-stats
   483→  app.get("/api/v2/checkpoints/:id/diff-stats", async (req, res) => {
   484→    try {
   485→      if (!repoDir) { res.json([]); return; }
   486→      const join = await db.checkpointIdGitOidJoin.findFirst({
   487→        where: { checkpointId: req.params.id },
   488→        select: { gitOid: true },
   489→      });
   490→      if (!join) { res.json([]); return; }
   491→      const { stdout } = await exec(
   492→        `git -C ${JSON.stringify(repoDir)} diff-tree --numstat -r ${join.gitOid}`,
   493→      );
   494→      const stats = stdout.trim().split("\n").filter(Boolean).map((line) => {
   495→        const [add, del, path] = line.split("\t");
   496→        return { path, additions: parseInt(add, 10) || 0, deletions: parseInt(del, 10) || 0 };
   497→      });
   498→      res.json(stats);
   499→    } catch {
   500→      res.json([]);
   501→    }
   502→  });
   503→
   504→  // GET /api/v2/sessions/:id/checkpoints
   505→  app.get("/api/v2/sessions/:id/checkpoints", async (req, res) => {
   506→    try {
   507→      const sessionId = req.params.id;
   508→      const sessionRows = await db.checkpointSessionMetadata.findMany({
   509→        where:   { sessionId },
   510→        orderBy: { createdAt: "asc" },
   511→        include: {
   512→          ...V2_SESSION_INCLUDE,
   513→          tokenUsage:   true,
   514→          filesTouched: { include: { filePath: true } },
   515→        },
   516→      });
   517→
   518→      res.json(sessionRows.map((s) => ({
   519→        checkpointId: s.checkpointId,
   520→        cliVersion:   s.cliVersion,
   521→        branch:       s.branch,
   522→        createdAt:    s.createdAt?.toISOString() ?? null,
   523→        tokenUsage:   s.tokenUsage ? {
   524→          inputTokens:         s.tokenUsage.inputTokens,
   525→          cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   526→          cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   527→          outputTokens:        s.tokenUsage.outputTokens,
   528→          apiCallCount:        s.tokenUsage.apiCallCount,
   529→        } : null,
   530→        filesTouched: s.filesTouched.map((f) => f.filePath.path),
   531→        summary:      s.summary ? mapV2Summary(s.summary) : null,
   532→      })));
   533→    } catch (err) {
   534→      res.status(500).json({ error: String(err) });
   535→    }
   536→  });
   537→
   538→  // PATCH /api/open-items/:id
   539→  app.patch("/api/open-items/:id", async (req, res) => {
   540→    const id = parseInt(req.params.id, 10);
   541→    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   542→    const allowed = ["open", "in_progress", "complete", "na"];
   543→    if (status !== undefined && !allowed.includes(status)) {
   544→      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   545→      return;
   546→    }
   547→    try {
   548→      const updated = await db.openItem.update({
   549→        where: { id },
   550→        data: {
   551→          ...(status !== undefined ? { status } : {}),
   552→          ...(subSessionId !== undefined ? { subSessionId } : {}),
   553→        },
   554→      });
   555→      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
   556→    } catch (err) {
   557→      res.status(500).json({ error: String(err) });
   558→    }
   559→  });
   560→
   561→  // POST /api/sessions/spawn
   562→  app.post("/api/sessions/spawn", async (req, res) => {
   563→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   564→    if (!prompt || typeof prompt !== "string") {
   565→      res.status(400).json({ error: "prompt is required" });
   566→      return;
   567→    }
   568→    try {
   569→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   570→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   571→      // Pass open item IDs and parent session so the SessionStart hook can link back
   572→      const envParts: string[] = [];
   573→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   574→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   575→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   576→      // Use AppleScript to open a new Terminal window running claude interactively
   577→      const script = [
   578→        `tell application "Terminal"`,
   579→        `  activate`,
   580→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   581→        `end tell`,
   582→      ].join("\n");
   583→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   584→      // Mark selected open items as in_progress
   585→      if (openItemIds?.length) {
   586→        await db.openItem.updateMany({
   587→          where: { id: { in: openItemIds } },
   588→          data: { status: "in_progress" },
   589→        });
   590→      }
   591→      res.json({ started: true });
   592→    } catch (err) {
   593→      res.status(500).json({ error: String(err) });
   594→    }
   595→  });
   596→
   597→  // POST /api/sessions/:id/resume
   598→  app.post("/api/sessions/:id/resume", (req, res) => {
   599→    const sessionId = req.params.id;
   600→    const { cwd } = req.body as { cwd?: string };
   601→    try {
   602→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   603→      const safeId = sessionId.replace(/'/g, "");
   604→      const script = [
   605→        `tell application "Terminal"`,
   606→        `  activate`,
   607→        `  do script "cd '${safeCwd}' && claude resume ${safeId}"`,
   608→        `end tell`,
   609→      ].join("\n");
   610→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   611→      res.json({ started: true });
   612→    } catch (err) {
   613→      res.status(500).json({ error: String(err) });
   614→    }
   615→  });
   616→
   617→  // GET /api/search?q=TEXT[&limit=N]
   618→  app.get("/api/search", async (req, res) => {
   619→    const q     = typeof req.query.q     === "string" ? req.query.q.trim()         : "";
   620→    const limit = typeof req.query.limit === "string" ? parseInt(req.query.limit)  : 50;
   621→    if (!q) { res.status(400).json({ error: "q is required" }); return; }
   622→    try {
   623→      const results = await searchLogContent(db, q, Math.min(limit, 200));
   624→      const sessionIds = [...new Set(results.map((r) => r.sessionId))];
   625→      const sessionMetas = sessionIds.length > 0
   626→        ? await db.checkpointSessionMetadata.findMany({
   627→            where: { sessionId: { in: sessionIds } },
   628→            select: { sessionId: true, checkpointId: true },
   629→            distinct: ["sessionId"],
   630→            orderBy: { createdAt: "desc" },
   631→          })
   632→        : [];
   633→      const cpIds = [...new Set(sessionMetas.map((m) => m.checkpointId))];
   634→      const cpUsers = cpIds.length > 0
   635→        ? await db.checkpointMetadata.findMany({
   636→            where: { checkpointId: { in: cpIds } },
   637→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   638→          })
   639→        : [];
   640→      const cpUserMap = new Map(cpUsers.map((r) => [r.checkpointId, r]));
   641→      const sessionUserMap = new Map(sessionMetas.map((m) => {
   642→        const u = cpUserMap.get(m.checkpointId);
   643→        return [m.sessionId, { gitUserName: u?.gitUserName ?? null, gitUserEmail: u?.gitUserEmail ?? null }];
   644→      }));
   645→      res.json(results.map((r) => {
   646→        const u = sessionUserMap.get(r.sessionId);
   647→        return { ...r, gitUserName: u?.gitUserName ?? gitUser.name, gitUserEmail: u?.gitUserEmail ?? gitUser.email };
   648→      }));
   649→    } catch (err) {
   650→      // FTS5 MATCH errors (bad syntax) come back as exceptions
   651→      res.status(400).json({ error: String(err) });
   652→    }
   653→  });
   654→
   655→  // Create HTTP server and attach WebSocket server (shared port)
   656→  const httpServer = createServer(app);
   657→  const wss = new WebSocketServer({ server: httpServer });
   658→
   659→  // WebSocket change detection — poll every 2s, broadcast on new log events, checkpoints, or shadow sessions
   660→  let lastMaxLogEventId: number | null = null;
   661→  let lastMaxCheckpointId: number | null = null;
   662→  let lastMaxShadowSessionId: number | null = null;
   663→  const broadcast = () => {
   664→    const message = JSON.stringify({ type: "sessions_updated" });
   665→    for (const client of wss.clients) {
   666→      if (client.readyState === WebSocket.OPEN) {
   667→        client.send(message);
   668→      }
   669→    }
   670→  };
   671→  const poller = setInterval(async () => {
   672→    try {
   673→      const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
   674→        db.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   675→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   676→        db.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   677→      ]);
   678→      const curLogEvent   = latestLogEvent?.id   ?? null;
   679→      const curCheckpoint = latestCheckpoint?.id ?? null;
   680→      const curShadow     = latestShadow?.id     ?? null;
   681→      if (curLogEvent !== lastMaxLogEventId || curCheckpoint !== lastMaxCheckpointId || curShadow !== lastMaxShadowSessionId) {
   682→        lastMaxLogEventId   = curLogEvent;
   683→        lastMaxCheckpointId = curCheckpoint;
   684→        lastMaxShadowSessionId = curShadow;
   685→        broadcast();
   686→      }
   687→    } catch {
   688→      // Non-fatal polling error — keep running
   689→    }
   690→  }, 2000);
   691→
   692→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   693→
   694→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   695→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   696→
   697→  if (repoDir) {
   698→    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   699→    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   700→
   701→    // Ensure worktree exists (reuse across restarts)
   702→    if (!existsSync(WORKTREE_PATH)) {
   703→      try {
   704→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   705→        execSync(
   706→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   707→          { stdio: "pipe" },
   708→        );
   709→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   710→      } catch (err) {
   711→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   712→      }
   713→    }
   714→
   715→    const runIndex = async () => {
   716→      if (!existsSync(WORKTREE_PATH)) return;
   717→      // Fetch to update remote tracking ref, then fast-forward local branch if possible.
   718→      // Always reset to the local branch tip so local-only commits are included.
   719→      try {
   720→        await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`, { timeout: 10_000 });
   721→      } catch { /* remote unavailable — index local state */ }
   722→      try {
   723→        // Use refs/heads/ explicitly to always resolve to the local branch, never the remote tracking ref
   724→        await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard refs/heads/${CHECKPOINT_BRANCH}`);
   725→      } catch { /* non-fatal */ }
   726→      try {
   727→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   728→        if (checkpoints > 0) {
   729→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   730→          broadcast();
   731→        }
   732→      } catch { /* non-fatal */ }
   733→    };
   734→
   735→    void runIndex();
   736→    checkpointPoller = setInterval(runIndex, 30_000);
   737→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   738→  }
   739→
   740→  // ── Shadow branch indexer ──────────────────────────────────────────────────
   741→
   742→  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   743→
   744→  if (repoDir) {
   745→    const runShadowIndex = async () => {
   746→      try {
   747→        const { sessions } = await indexAllShadowBranches(db, repoDir);
   748→        if (sessions > 0) broadcast();
   749→      } catch { /* non-fatal */ }
   750→    };
   751→
   752→    void runShadowIndex();
   753→    shadowPoller = setInterval(runShadowIndex, 5_000);
   754→    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   755→  }
   756→
   757→  // Graceful shutdown
   758→  const shutdown = () => {
   759→    clearInterval(poller);
   760→    if (checkpointPoller) clearInterval(checkpointPoller);
   761→    if (shadowPoller) clearInterval(shadowPoller);
   762→    httpServer.close();
   763→    process.exit(0);
   764→  };
   765→  process.on("SIGINT", shutdown);
   766→  process.on("SIGTERM", shutdown);
   767→
   768→  await new Promise<void>((resolve) => {
   769→    httpServer.listen(port, () => {
   770→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   771→      resolve();
   772→    });
   773→  });
   774→}
