    42→  sessionId: string;
    43→  summary: string;
    44→  keywords: string[];
    45→  startedAt: string;
    46→  endedAt: string;
    47→}
    48→
    49→export async function fetchSessions(): Promise<Session[]> {
    50→  const res = await fetch(`${API_BASE}/sessions`);
    51→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    52→  return res.json() as Promise<Session[]>;
    53→}
    54→
    55→export async function fetchSession(id: string): Promise<Session> {
    56→  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}`);
    57→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    58→  return res.json() as Promise<Session>;
    59→}
    60→
    61→export async function fetchSessionOverview(id: string): Promise<InteractionOverview | null> {
    62→  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}/overview`);
    63→  if (res.status === 404) return null;
    64→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    65→  return res.json() as Promise<InteractionOverview>;
    66→}
    67→
    68→export async function fetchSessionEvents(id: string): Promise<Event[]> {
    69→  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}/events`);
    70→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    71→  return res.json() as Promise<Event[]>;
    72→}
    73→
    74→export interface OpenItem {
    75→  id: number;
    76→  text: string;
    77→  status: "open" | "in_progress" | "complete" | "na";
    78→  subSessionId: string | null;
    79→}
    80→
    81→export interface CheckpointSummary {
    82→  intent: string;
    83→  outcome: string;
    84→  repoLearnings: string[];
    85→  codeLearnings: Array<{ path: string; finding: string }>;
    86→  workflowLearnings: string[];
    87→  friction: string[];
    88→  openItems: OpenItem[];
    89→}
    90→
    91→export interface TokenUsage {
    92→  inputTokens: number;
    93→  cacheCreationTokens: number;
    94→  cacheReadTokens: number;
    95→  outputTokens: number;
    96→  apiCallCount: number;
    97→}
    98→
    99→export interface Checkpoint {
   100→  id: number;
   101→  checkpointId: string;
   102→  branch: string | null;
   103→  cliVersion: string | null;
   104→  strategy: string | null;
   105→  checkpointsCount: number;
