  const [copied, setCopied] = useState(false);

  function copy(e: React.MouseEvent) {
    e.stopPropagation();
    navigator.clipboard.writeText(copyValue).catch(() => undefined);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  }

  return (
    <Table.Td
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setHovered(false); setCopied(false); }}
      style={{ width, maxWidth: width, overflow: "hidden", position: "relative", paddingRight: hovered ? 28 : undefined }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
        {prefix}
        <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>
          {children}
        </div>
      </div>
      {hovered && copyValue && (
        <Tooltip label={copied ? "Copied!" : "Copy"} withArrow position="top" openDelay={0}>
          <ActionIcon
            size="xs"
            variant="subtle"
            color={copied ? "green" : "gray"}
            onClick={copy}
            style={{ position: "absolute", right: 4, top: "50%", transform: "translateY(-50%)" }}
          >
            {copied ? "✓" : "⧉"}
          </ActionIcon>
        </Tooltip>
      )}
    </Table.Td>
  );
}

export function SessionRow({ session, onPress }: Props) {
  const dot = activityDot(session.updatedAt);
  const intent = session.intent ?? session.summary ?? session.prompt?.slice(0, 160) ?? "—";
  const shortId = session.sessionId.slice(0, 8) + "…";
  const shortParent = session.parentSessionId ? session.parentSessionId.slice(0, 8) + "…" : null;
  const [resuming, setResuming] = useState(false);

  return (
    <>
      <Table.Tr onClick={onPress} style={{ cursor: "pointer" }}>
        <CopyCell
          copyValue={session.sessionId}
          width={COL_WIDTHS.sessionId}
          prefix={
            <Tooltip label={dot.label} withArrow position="left" openDelay={300}>
              <div style={{ width: 8, height: 8, borderRadius: "50%", backgroundColor: dot.color, flexShrink: 0 }} />
            </Tooltip>
          }
        >
          <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
            <Text ff="monospace" size="sm" c="indigo" style={{ flexShrink: 0 }}>
              {shortId}
            </Text>
            <Tooltip label="Resume in terminal" withArrow position="top" openDelay={300}>
              <ActionIcon
                size="sm"
                variant="light"
                color="indigo"
                loading={resuming}
                style={{ flexShrink: 0 }}
                onClick={async (e) => {
                  e.stopPropagation();
                  setResuming(true);
                  try { await resumeSession(session.sessionId, session.cwd); }
                  finally { setResuming(false); }
                }}
              >
                →
              </ActionIcon>
            </Tooltip>
            {session.isLive && (
              <Badge size="xs" color="orange" variant="light" style={{ flexShrink: 0 }}>
                live
              </Badge>
            )}
          </div>
        </CopyCell>

        <CopyCell copyValue={session.gitUserEmail ?? session.gitUserName ?? ""} width={COL_WIDTHS.user}>
          {session.gitUserEmail ? (
            <Anchor
              size="sm"
              href={`mailto:${session.gitUserEmail}`}
              onClick={(e) => e.stopPropagation()}
            >
              {session.gitUserName ?? session.gitUserEmail}
            </Anchor>
          ) : (
            <Text size="sm" c={session.gitUserName ? undefined : "dimmed"}>
              {session.gitUserName ?? "—"}
            </Text>
          )}
        </CopyCell>

        <CopyCell copyValue={session.branch ?? ""} width={COL_WIDTHS.branch}>
          <Text size="sm" ff="monospace" c={session.branch ? "teal" : "dimmed"}>
            {session.branch ?? "—"}
          </Text>
        </CopyCell>

        <CopyCell copyValue={intent} width={COL_WIDTHS.intent}>
          <Text size="sm">{intent}</Text>
        </CopyCell>

        <CopyCell copyValue={session.parentSessionId ?? ""} width={COL_WIDTHS.parentSessionId}>
          {shortParent ? (
            <Text ff="monospace" size="sm" c="blue">{shortParent}</Text>
          ) : (
            <Text size="sm" c="dimmed">—</Text>
          )}
        </CopyCell>

        <CopyCell copyValue={absoluteTime(session.startedAt)} width={COL_WIDTHS.started}>
          <Text size="sm" c="dimmed">{relativeTime(session.startedAt)}</Text>
        </CopyCell>

        <CopyCell copyValue={absoluteTime(session.updatedAt)} width={COL_WIDTHS.updated}>
          <Text size="sm" c="dimmed">{relativeTime(session.updatedAt)}</Text>
        </CopyCell>
      </Table.Tr>
    </>
  );
}

import React, { useEffect, useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { Center, Loader, Alert, Text, Table, Box } from "@mantine/core";
import { fetchSessions, subscribeToUpdates, type Session } from "../api";
import { SessionRow, COL_WIDTHS } from "../components/SessionRow";
import { useBreadcrumb } from "../BreadcrumbContext";

const COLUMNS: { label: string; width: number }[] = [
  { label: "Session ID",  width: COL_WIDTHS.sessionId      },
  { label: "User",        width: COL_WIDTHS.user            },
  { label: "Branch",      width: COL_WIDTHS.branch          },
  { label: "Intent",      width: COL_WIDTHS.intent           },
  { label: "Parent",      width: COL_WIDTHS.parentSessionId },
  { label: "Started",     width: COL_WIDTHS.started         },
  { label: "Updated",     width: COL_WIDTHS.updated         },
];

const TOTAL_WIDTH = Object.values(COL_WIDTHS).reduce((a, b) => a + b, 0) + 16;

export function ActiveSessions() {
  const navigate = useNavigate();
  const [sessions, setSessions] = useState<Session[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { setCrumbs } = useBreadcrumb();

  const load = useCallback(async () => {
    try {
      const data = await fetchSessions();
      setSessions(data);
      setError(null);
      return data;
    } catch (err) {
      setError(String(err));
      return [] as Session[];
    }
  }, []);

  useEffect(() => {
    load().then((data) => {
      const first = data[0];
      const user = first?.gitUserName ?? first?.gitUserEmail ?? null;
      const repo = first?.repoName ?? null;
      setCrumbs([
        ...(user ? [{ label: user }] : []),
        ...(repo ? [{ label: repo }] : []),
      ]);
    }).finally(() => setLoading(false));
    return subscribeToUpdates(() => { load().catch(() => undefined); });
  }, [load]);

  if (loading) {
    return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
  }

  if (error) {
    return (
      <Center style={{ flex: 1, padding: 24 }}>
        <Alert color="red" title="Cannot reach API server" maw={480}>
          <Text size="sm" mb={4}>
            Start the server with:{" "}
            <Text component="span" ff="monospace" size="sm">claude-hook-handler serve</Text>
          </Text>
          <Text size="xs" c="dimmed">{error}</Text>
        </Alert>
      </Center>
    );
  }

  if (sessions.length === 0) {
    return <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No sessions yet.</Text></Center>;
  }

  return (
    <Box style={{ flex: 1, overflow: "hidden" }}>
      <Table.ScrollContainer minWidth={TOTAL_WIDTH} h="100%">
        <Table stickyHeader highlightOnHover>
          <Table.Thead>
            <Table.Tr>
              {COLUMNS.map(({ label, width }) => (
                <Table.Th key={label} style={{ width, fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
                  {label}
                </Table.Th>
              ))}
            </Table.Tr>
          </Table.Thead>
          <Table.Tbody>
            {sessions.map((item) => (
              <SessionRow
                key={item.sessionId}
                session={item}
                onPress={() =>
                  navigate(`/sessions/${item.sessionId}`, {
                    state: { title: item.summary ?? item.sessionId.slice(0, 8) + "…" },
                  })
                }
              />
            ))}
          </Table.Tbody>
        </Table>
      </Table.ScrollContainer>
    </Box>
  );
}

