// DELETE /api/repos — remove a repo by localPath { localPath }
app.delete("/api/repos", (req, res) => {
  try {
    const { localPath } = req.body as { localPath?: string };
    if (!localPath) {
      res.status(400).json({ error: "localPath is required" });
