// GET /api/checkpoints/:id/messages — log events linked to this checkpoint via SessionLinks
app.get("/api/checkpoints/:id/messages", async (req, res) => {
  try {
    const checkpointId = req.params.id;
    const checkpoint = await db.checkpointMetadata.findUnique({
      where: { checkpointId },
      include: {
        sessions: {
          include: {
            logEvents: { orderBy: { id: "asc" } },
          },
        },
      },
    });
    if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }

    const messages = checkpoint.sessions
      .flatMap((s) => s.logEvents)
      .sort((a, b) => a.id - b.id)
      .map((e) => ({
        id:             e.id,
        uuid:           e.uuid,
        sessionId:      e.sessionId,
        parentUuid:     e.parentUuid,
        type:           e.type,
        timestamp:      e.timestamp?.toISOString() ?? null,
        gitBranch:      e.gitBranch,
        slug:           e.slug,
        planContent:    null,
        toolUseId:      e.toolUseId,
        parentToolUseId: e.parentToolUseId,
        data:           JSON.parse(e.data) as unknown,
      }));

    res.json(messages);
  } catch (err) {
    res.status(500).json({ error: String(err) });
  }
});

