   592→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   593→  const searchSnippet = (location.state as { snippet?: string; contentType?: string } | null)?.snippet ?? null;
   594→  const searchContentType = (location.state as { snippet?: string; contentType?: string } | null)?.contentType ?? null;
   595→  const [highlightActive, setHighlightActive] = useState(false);
   596→  const scrolledRef = useRef(false);
   597→  const viewportRef = useRef<HTMLDivElement>(null);
   598→  const logEventsRef = useRef<LogEventItem[]>([]);
   599→  const [session, setSession] = useState<Session | null>(null);
   600→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   601→  const [items, setItems] = useState<RenderItem[]>([]);
   602→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   603→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   604→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   605→  const [spawning, setSpawning] = useState(false);
   606→  const [loading, setLoading] = useState(true);
   607→  const [error, setError] = useState<string | null>(null);
   608→
   609→  const id = sessionId!;
   610→  const { setCrumbs } = useBreadcrumb();
   611→
   612→  function applyCheckpoints(logEvs: LogEventItem[], checkpoints: SessionCheckpoint[]) {
   613→    const grouped = groupEvents(logEventsToEvents(logEvs));
   614→    const merged: DisplayItem[] = [];
   615→    let cpIdx = 0;
   616→    const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   617→    const latest = sortedCps[sortedCps.length - 1] ?? null;
   618→    setLatestCheckpoint(latest);
   619→    setOpenItems(latest?.summary?.openItems ?? []);
   620→
   621→    for (const item of grouped) {
   622→      const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   623→      while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   624→        merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   625→      }
   626→      merged.push(item);
   627→    }
   628→    while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   629→    setItems(groupClaudeTurns(merged));
   630→  }
   631→
   632→  // Initial load
   633→  useEffect(() => {
   634→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   635→      .then(([s, logEvs, checkpoints]) => {
   636→        logEventsRef.current = logEvs;
   637→        setSession(s);
   638→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   639→        const repo = s.repoName ?? null;
   640→        const shortId = s.sessionId.slice(0, 8) + "…";
   641→        if (user) {
   642→          setUserInfo({
   643→            name: s.gitUserName ?? user,
   644→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   645→          });
   646→        }
