   651→        ]);
   652→        applyCheckpoints(logEvs, checkpoints);
   653→        setError(null);
   654→      })
   655→      .catch((err: unknown) => setError(String(err)))
   656→      .finally(() => setLoading(false));
   657→  }, [id]);
   658→
   659→  // Live updates: re-fetch checkpoints and log events when the server broadcasts a change
   660→  useEffect(() => {
   661→    return subscribeToUpdates(() => {
   662→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   663→        .then(([logEvs, checkpoints]) => applyCheckpoints(logEvs, checkpoints))
   664→        .catch(() => undefined);
   665→    });
   666→  }, [id]);
   667→
   668→  // Step 1: activate highlight once items are loaded (triggers Collapse expand + mark rendering)
   669→  useEffect(() => {
   670→    if (targetLogEventId === null || items.length === 0 || scrolledRef.current) return;
   671→    const t = setTimeout(() => {
   672→      setHighlightActive(true);
   673→      scrolledRef.current = true;
   674→      setTimeout(() => setHighlightActive(false), 10000);
   675→    }, 150);
   676→    return () => clearTimeout(t);
   677→  }, [items, targetLogEventId]);
   678→
   679→  // Step 2: once highlightActive is true (marks rendered, Collapses expanding), scroll to first <mark>
