  return (
    <Box style={{ display: "flex", padding: "12px 20px 4px", gap: 10 }}>
      <img src={claudeLogo} alt="Claude" style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, marginTop: 2 }} />
