          </Box>
        )}
        {stop && msg && (
          <Box style={{
            backgroundColor: "light-dark(var(--mantine-color-white), var(--mantine-color-dark-6))",
            border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4))",
