app.get("/api/v2/checkpoints/:id/diff", async (req, res) => {
  try {
    const checkpointId = req.params.id;
    const cdb = await dbForCheckpoint(db, dbPath, checkpointId);
    const join = await cdb.checkpointIdGitOidJoin.findFirst({
      where: { checkpointId },
      select: { gitOid: true },
    });
