    const { stdout } = await exec(
      `git -C ${JSON.stringify(localPath)} diff-tree -p --no-commit-id -r ${join.gitOid}`,
    );
    res.set("Content-Type", "text/plain; charset=utf-8");
    res.send(stdout);
  } catch {
