// GET /api/v2/checkpoints/:id/diff-stats
app.get("/api/v2/checkpoints/:id/diff-stats", async (req, res) => {
  try {
    const checkpointId = req.params.id;
    const cdb = await dbForCheckpoint(db, dbPath, checkpointId);
    const join = await cdb.checkpointIdGitOidJoin.findFirst({
      where: { checkpointId },
      select: { gitOid: true },
    });
    if (!join) { res.json([]); return; }
    const localPath = readConfig().repos.find((r) => r.dbPath === (cdb === db ? dbPath : readConfig().repos.find((r2) => r2.dbPath !== dbPath)?.dbPath))?.localPath ?? repoDir;
    if (!localPath) { res.json([]); return; }
    const { stdout } = await exec(
      `git -C ${JSON.stringify(localPath)} diff-tree --numstat -r ${join.gitOid}`,
    );
    const stats = stdout.trim().split("\n").filter(Boolean).map((line) => {
      const [add, del, path] = line.split("\t");
      return { path, additions: parseInt(add, 10) || 0, deletions: parseInt(del, 10) || 0 };
    });
    res.json(stats);
  } catch {
    res.json([]);
  }
});

