import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { Center, Loader, Text, ScrollArea, Box, Badge, Group, Anchor } from "@mantine/core";
import { fetchCheckpoint, fetchCheckpointDiff, type Checkpoint, type CheckpointSummary } from "../api";
import { html as diff2htmlHtml } from "diff2html";
import "diff2html/bundles/css/diff2html.min.css";
import "../diff2html-theme.css";
import { InlineMarkdown } from "../components/MarkdownView";

function SummaryCard({ summary }: { summary: CheckpointSummary }) {
  return (
    <Box style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <Box>
        <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>Intent</Text>
        <Text size="sm">{summary.intent}</Text>
      </Box>
      {summary.outcome && (
        <Box>
          <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>Outcome</Text>
          <InlineMarkdown text={summary.outcome} style={{ fontSize: 13, lineHeight: 1.6 }} />
        </Box>
      )}
      {summary.openItems.length > 0 && (
        <Box>
          <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={6}>Open items</Text>
          {summary.openItems.map((it) => {
            const color = it.status === "complete" ? "teal" : it.status === "in_progress" ? "orange" : it.status === "na" ? "gray" : "blue";
            const label = it.status === "in_progress" ? "in progress" : it.status === "na" ? "n/a" : it.status;
            return (
              <Group key={it.id} gap={8} mb={4} wrap="nowrap" align="flex-start">
                <Badge color={color} size="xs" variant="light" style={{ flexShrink: 0, marginTop: 2 }}>{label}</Badge>
                <Text size="xs" lh={1.5}>{it.text}</Text>
              </Group>
            );
          })}
        </Box>
      )}
      {summary.repoLearnings.length > 0 && (
        <Box>
          <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={4}>Repo learnings</Text>
          {summary.repoLearnings.map((t, i) => <InlineMarkdown key={i} text={`· ${t}`} style={{ fontSize: 12, lineHeight: 1.8 }} />)}
        </Box>
      )}
      {summary.friction.length > 0 && (
        <Box>
          <Text size="xs" fw={700} c="orange" tt="uppercase" mb={4}>Friction</Text>
          {summary.friction.map((t, i) => <InlineMarkdown key={i} text={`· ${t}`} style={{ fontSize: 12, lineHeight: 1.8 }} />)}
        </Box>
      )}
    </Box>
  );
}

export function CheckpointDetail() {
  const navigate = useNavigate();
  const { checkpointId } = useParams<{ checkpointId: string }>();
  const [checkpoint, setCheckpoint] = useState<Checkpoint | null>(null);
  const [diff, setDiff] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const id = checkpointId!;

  useEffect(() => {
    fetchCheckpoint(id)
      .then((cp) => {
        setCheckpoint(cp);
        setError(null);
        return fetchCheckpointDiff(id);
      })
      .then((d) => setDiff(d ?? ""))
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
  if (error)   return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
  if (!checkpoint) return null;

  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;

  return (
    <ScrollArea style={{ flex: 1 }}>
      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>

        {/* Header */}
        <Box p="lg" style={{ borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))" }}>
          <Group gap={10} mb={6} wrap="wrap">
            <Text ff="monospace" fw={700} c="teal">{checkpoint.checkpointId}</Text>
            {checkpoint.branch && (
              <Anchor
                ff="monospace"
                size="sm"
                c="blue"
                underline="never"
                style={{ cursor: "pointer" }}
                onClick={() => navigate(`/checkpoints/timeline`)}
              >
                <Badge variant="light" color="teal">{checkpoint.branch}</Badge>
              </Anchor>
            )}
            {outTokens > 0 && <Text size="xs" c="dimmed" ff="monospace">{outTokens.toLocaleString()} tokens</Text>}
            {checkpoint.filesTouched.length > 0 && (
              <Text size="xs" c="dimmed">{checkpoint.filesTouched.length} file{checkpoint.filesTouched.length !== 1 ? "s" : ""} changed</Text>
            )}
          </Group>
        </Box>

        {/* Summary */}
        {checkpoint.summary && (
          <Box p="lg" style={{ borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))" }}>
            <Text size="xs" fw={700} c="teal" tt="uppercase" mb={12} style={{ letterSpacing: 0.5 }}>Summary</Text>
            <SummaryCard summary={checkpoint.summary} />
          </Box>
        )}

        {/* Diff */}
        <Box p="lg">
          <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={10} style={{ letterSpacing: 0.5 }}>Files changed</Text>
          {diff === null ? (
            <Text size="xs" c="dimmed">Loading…</Text>
          ) : diff === "" ? (
            checkpoint.filesTouched.length > 0 ? (
              <Box style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                {checkpoint.filesTouched.map((path) => (
                  <Text key={path} size="xs" ff="monospace" c="dimmed">{path}</Text>
                ))}
              </Box>
            ) : (
              <Text size="xs" c="dimmed">No diff available</Text>
            )
          ) : (
            <Box
              className="d2h-wrapper"
              style={{ fontSize: 12, overflowX: "auto" }}
              dangerouslySetInnerHTML={{
                __html: diff2htmlHtml(diff, {
                  drawFileList: true,
                  matching: "lines",
                  outputFormat: "line-by-line",
                  colorScheme: "light",
                }),
              }}
            />
          )}
        </Box>

      </Box>
    </ScrollArea>
  );
}

