  useEffect(() => {
    fetchCheckpoint(id)
      .then((cp) => { setCheckpoint(cp); setError(null); })
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
  if (error)   return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
  if (!checkpoint) return null;

  const sc = toSessionCheckpoint(checkpoint);

  return (
    <ScrollArea style={{ flex: 1 }}>
      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
        <CheckpointRow
          checkpoint={sc}
          onPress={() => {
            if (checkpoint.branch) {
              // navigate to branch log if we know the branch
            }
            navigate(`/checkpoints/${checkpoint.checkpointId}`);
          }}
        />
      </Box>
    </ScrollArea>
  );
}

