let currentBranch: string | null = null;
try {
  const { stdout } = await exec(`git -C ${JSON.stringify(repo.localPath)} branch --show-current`);
  currentBranch = stdout.trim() || null;
} catch { /* not a git repo or path missing */ }
if (!currentBranch) {
  try {
    const { stdout } = await exec(`git -C ${JSON.stringify(repo.localPath)} symbolic-ref --short HEAD`);
    currentBranch = stdout.trim() || null;
  } catch { /* detached HEAD or not a git repo */ }
}

let latestCheckpointId: string | null = null;
let gitUserName: string | null = null;
let gitUserEmail: string | null = null;
try {
  const repoDb = await getDb(repo.dbPath);
  const latest = await repoDb.checkpointMetadata.findFirst({
    orderBy: { id: "desc" },
    select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
  });
  latestCheckpointId = latest?.checkpointId ?? null;
  gitUserName       = latest?.gitUserName  ?? null;
  gitUserEmail      = latest?.gitUserEmail ?? null;
} catch { /* db may not exist yet */ }

// Git fallback: read checkpoint tree from entire/checkpoints/v1 branch
if (!latestCheckpointId) {
  try {
    const { stdout: shardOut } = await exec(
      `git -C ${JSON.stringify(repo.localPath)} ls-tree --name-only entire/checkpoints/v1`,
      { timeout: 5000 },
    );
    const shards = shardOut.trim().split("\n")
      .filter((s) => /^[0-9a-f]{2}$/i.test(s))
      .sort();
    if (shards.length > 0) {
      const lastShard = shards[shards.length - 1];
      const { stdout: cpOut } = await exec(
        `git -C ${JSON.stringify(repo.localPath)} ls-tree --name-only entire/checkpoints/v1:${lastShard}`,
        { timeout: 5000 },
      );
      const cps = cpOut.trim().split("\n")
        .filter((s) => /^[0-9a-f]{10}$/i.test(s))
        .sort();
      if (cps.length > 0) {
        latestCheckpointId = lastShard + cps[cps.length - 1];
      }
    }
  } catch { /* no entire/checkpoints/v1 branch or git unavailable */ }
}

