#!/usr/bin/env node
import { startServer } from "./server.js";
import { readConfig } from "./config.js";

const args = process.argv.slice(2);
const get = (flag: string, def: string): string => {
  const i = args.indexOf(flag);
  return i !== -1 && args[i + 1] ? args[i + 1] : def;
};

const defaultDb = `${process.env.HOME ?? "~"}/.claude/hook-handler.db`;
const repoDir   = get("--repo-dir", process.cwd());
const port      = parseInt(get("--port", "3000"), 10);

// Resolve dbPath: if repoDir matches a config entry use its dbPath, otherwise fall back to --db
const config    = readConfig();
const repoEntry = config.repos.find((r) => r.localPath === repoDir);
const dbPath    = repoEntry?.dbPath ?? get("--db", defaultDb);

await startServer(dbPath, port, repoDir);

