    try {
      const results = await searchLogContent(db, q, Math.min(limit, 200));
      const sessionIds = [...new Set(results.map((r) => r.sessionId))];
      const sessionMetas = sessionIds.length > 0
        ? await db.checkpointSessionMetadata.findMany({
