          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
        return {
          id:               c.id,
          checkpointId:     c.checkpointId,
          cliVersion:       c.cliVersion,
          strategy:         c.strategy,
          branch:           c.branch,
          checkpointsCount: c.checkpointsCount,
          createdAt:        latestCreatedAt?.toISOString() ?? null,
          tokenUsage: c.tokenUsage ? {
